为了接收员工的用户名和密码，我們可以建立一个简单的 PHP 程式：

```php
<?php
header('Location: index.php?redirectTo=verifyLogin');
$_SERVER['REQUEST_METHOD'] = 'POST';

// 定义验证逻辑
function isLoggedIninUser($username, $password) {
    $users = [
        ['username' => 'admin', 'password' => 'admin'],
        ['username' => 'user1', 'password' => 'user1'],
        ['username' => 'user2', 'password' => 'user2']
    ];

    foreach ($users as $user) {
        if ($user['username'] === $username && $user['password'] === $password) {
            return true;
        }
    }

    return false;
}

// 获取表单数据
$username = $_SERVER['HTTP_USER Input'];
$password = $_SERVER['HTTP_PASSWORD'];

// 进行验证
if (isLoggedIninUser($username, $password)) {
    echo "欢迎光临！";
    exit;
}

echo "请输入正确的用户名和密码";
?>
